1	import cors from '@fastify/cors';
2	import cookie from '@fastify/cookie';
3	import jwt from '@fastify/jwt';
4	import swagger from '@fastify/swagger';
5	import swaggerUi from '@fastify/swagger-ui';
6	import Fastify from 'fastify';
7	import Redis from 'ioredis';
8	
9	import { getConfig } from './lib/config';
10	import { normalizeError, normalizeErrorPayload } from './lib/errors';
11	import { buildLoggerOptions, childRequestLogger } from './lib/logger';
12	import { prisma } from './lib/prisma';
13	import { AUTH_COOKIE_NAME } from './modules/auth/auth.constants';
14	import { resolveApiPrefix } from './modules/api/api-versioning';
15	import { requireAuth } from './modules/auth/auth.middleware';
16	import { createAuditOnResponseHook } from './modules/audit/audit.hooks';
17	import { v1Routes } from './modules/api/v1.routes';
18	import { createIdempotencyMiddleware } from './modules/security/idempotency.middleware';
19	import { createUserRateLimitMiddleware } from './modules/security/rate-limit.middleware';
20	import { createSignedRequestMiddleware } from './modules/security/signed-request.middleware';
21	import { isProtectedBusinessAction } from './modules/security/security.utils';
22	
23	export function buildApp() {
24	  const config = getConfig();
25	  const app = Fastify({ logger: buildLoggerOptions(), trustProxy: config.TRUST_PROXY });
26	  const exposeOperationalDetails = config.NODE_ENV === 'development';
27	
28	  app.addHook('onRequest', async (request) => {
29	    const path = request.url.split('?')[0] || '/';
30	    const module = path.split('/').filter(Boolean)[2] || 'system';
31	    const action = `${request.method.toUpperCase()} ${path}`;
32	    (request as any).log = childRequestLogger(request.log, {
33	      correlationId: request.id,
34	      module,
35	      action
36	    });
37	  });
38	
39	  app.addHook('preHandler', async (request) => {
40	    if (request.user?.sub) {
41	      (request as any).log = request.log.child({ userId: request.user.sub });
42	    }
43	  });
44	
45	  app.register(cors, {
46	    origin: config.CORS_ORIGINS,
47	    credentials: true
48	  });
49	
50	  if (exposeOperationalDetails) {
51	    app.register(swagger, {
52	      stripBasePath: false,
53	      openapi: {
54	        openapi: '3.0.3',
55	        info: {
56	          title: 'Culinary Studio API',
57	          description: 'Versioned backend APIs for operations, billing, workflows, notifications, and analytics.',
58	          version: '1.0.0'
59	        },
60	        servers: [{ url: '/' }],
61	        tags: [
62	          { name: 'auth' },
63	          { name: 'analytics' },
64	          { name: 'billing' },
65	          { name: 'bookings' },
66	          { name: 'notifications' },
67	          { name: 'webhooks' },
68	          { name: 'workflows' },
69	          { name: 'system' }
70	        ]
71	      }
72	    });
73	
74	    app.register(swaggerUi, {
75	      routePrefix: '/api/docs'
76	    });
77	  }
78	
79	  app.register(cookie, {
80	    hook: 'onRequest',
81	    parseOptions: {
82	      secure: true,
83	      httpOnly: true,
84	      sameSite: 'strict'
85	    }
86	  });
87	
88	  app.register(jwt, {
89	    secret: config.JWT_ACCESS_SECRET,
90	    cookie: {
91	      cookieName: AUTH_COOKIE_NAME,
92	      signed: false
93	    }
94	  });
95	
96	  app.addHook('preHandler', async (request, reply) => {
97	    if (!isProtectedBusinessAction(request)) {
98	      return;
99	    }
100	
101	    await requireAuth(request, reply);
102	  });
103	
104	  app.addHook('preHandler', createUserRateLimitMiddleware(app));
105	  app.addHook('preHandler', createSignedRequestMiddleware());
106	
107	  const idempotencyMiddleware = createIdempotencyMiddleware();
108	  app.addHook('preHandler', idempotencyMiddleware.preHandler);
109	  app.addHook('onSend', idempotencyMiddleware.onSend);
110	  app.addHook('onSend', async (_request, reply, payload) => {
111	    if (reply.statusCode < 400) {
112	      return payload;
113	    }
114	
115	    if (typeof payload === 'string') {
116	      try {
117	        const parsed = JSON.parse(payload);
118	        return JSON.stringify(normalizeErrorPayload(parsed, reply.statusCode));
119	      } catch {
120	        return payload;
121	      }
122	    }
123	
124	    return normalizeErrorPayload(payload, reply.statusCode);
125	  });
126	
127	  app.setErrorHandler((error, request, reply) => {
128	    if (reply.sent) {
129	      request.log.warn({ err: error }, 'Error occurred after reply already sent');
130	      return;
131	    }
132	
133	    const normalized = normalizeError(error, config.NODE_ENV);
134	    const level = normalized.statusCode >= 500 ? 'error' : 'warn';
135	    request.log[level]({ err: error, statusCode: normalized.statusCode }, 'Unhandled request error');
136	    reply.code(normalized.statusCode).send(normalized.body);
137	  });
138	
139	  app.addHook('onResponse', async (request, reply) => {
140	    const isMutation = ['POST', 'PUT', 'PATCH', 'DELETE'].includes(request.method.toUpperCase());
141	    const isAuthPath = request.url.startsWith('/api/v1/auth/');
142	
143	    if (reply.statusCode >= 500) {
144	      request.log.error({ statusCode: reply.statusCode }, 'Request completed with server error');
145	      return;
146	    }
147	
148	    if (reply.statusCode >= 400) {
149	      request.log.warn({ statusCode: reply.statusCode }, 'Request completed with client error');
150	      return;
151	    }
152	
153	    if (isMutation || isAuthPath) {
154	      request.log.info({ statusCode: reply.statusCode }, 'Request completed');
155	    }
156	  });
157	
158	  app.addHook('onResponse', createAuditOnResponseHook());
159	
160	  app.register(v1Routes, { prefix: resolveApiPrefix('v1') });
161	
162	  app.get('/health', {
163	    schema: {
164	      tags: ['system'],
165	      summary: 'Service liveness check',
166	      response: {
167	        200: {
168	          type: 'object',
169	          properties: {
170	            status: { type: 'string' }
171	          }
172	        }
173	      }
174	    }
175	  }, async () => ({ status: 'ok' }));
176	
177	  app.get('/health/ready', {
178	    schema: {
179	      tags: ['system'],
180	      summary: 'Service readiness check',
181	      response: {
182	        200: {
183	          type: 'object',
184	          properties: {
185	            status: { type: 'string' },
186	            checks: { type: 'object' }
187	          }
188	        },
189	        503: {
190	          type: 'object',
191	          properties: {
192	            status: { type: 'string' },
193	            checks: { type: 'object' }
194	          }
195	        }
196	      }
197	    }
198	  }, async (_request, reply) => {
199	    const checks: Record<string, { ok: boolean; details?: string }> = {
200	      config: { ok: true }
201	    };
202	
203	    try {
204	      await prisma.$queryRaw`SELECT 1`;
205	      checks.database = { ok: true };
206	    } catch {
207	      checks.database = { ok: false, details: 'Database connection failed' };
208	    }
209	
210	    if (config.REDIS_URL) {
211	      const redis = new Redis(config.REDIS_URL, {
212	        maxRetriesPerRequest: 0,
213	        lazyConnect: true
214	      });
215	
216	      try {
217	        await redis.connect();
218	        await redis.ping();
219	        checks.redis = { ok: true };
220	      } catch {
221	        checks.redis = { ok: false, details: 'Redis connection failed' };
222	      } finally {
223	        redis.disconnect();
224	      }
225	    } else {
226	      checks.redis = { ok: true, details: 'Redis not configured' };
227	    }
228	
229	    const allReady = Object.values(checks).every((value) => value.ok);
230	     const status = allReady ? 'ready' : 'not_ready';
231	     return reply.code(allReady ? 200 : 503).send(
232	       exposeOperationalDetails
233	         ? {
234	             status,
235	             checks
236	           }
237	         : {
238	             status
239	           }
240	     );
241	   });
242	
243	  return app;
244	}
