**requireRoles Middleware:**
```typescript
export function requireRoles(allowedRoles: string[]) {
  return async function roleGuard(request: FastifyRequest, reply: FastifyReply): Promise<void> {
    try {
      await request.jwtVerify();
    } catch {
      return reply.code(401).send({ message: 'Unauthorized' });  // JWT verify fails
    }

    const roles = request.user.roles ?? [];
    const hasRequiredRole = allowedRoles.some((role) => roles.includes(role));

    if (!hasRequiredRole) {
      return reply.code(403).send({ message: 'Forbidden' });  // JWT valid but wrong role
    }
  };
}
```

**HTTP Response Codes:**
- **401 Unauthorized** - No valid JWT token / JWT verification failed
- **403 Forbidden** - Valid JWT but insufficient roles/permissions
- **500 Internal Server Error** - Unhandled exceptions

