        endAt: '2026-04-10T11:00:00.000Z',
        capacity: 4
      }
    });

    // Should not be 400 (schema rejection) - may fail at DB level
    expect(response.statusCode).not.toBe(400);
  });

  it('rejects booking creation with invalid userId format', async () => {
