1	import type { FastifyInstance, FastifyReply, FastifyRequest, preHandlerHookHandler } from 'fastify';
2	import { getConfig } from '../../lib/config';
3	
4	import { AUTH_COOKIE_NAME } from '../auth/auth.constants';
5	
6	type Bucket = {
7	  count: number;
8	  resetAt: number;
9	};
10	
11	const buckets = new Map<string, Bucket>();
12	
13	async function resolveRateLimitKey(app: FastifyInstance, request: FastifyRequest): Promise<string> {
14	  const token = request.cookies[AUTH_COOKIE_NAME];
15	
16	  if (token) {
17	    try {
18	      const payload = await app.jwt.verify<{ sub?: string }>(token);
19	      if (payload.sub) {
20	        return `user:${payload.sub}`;
21	      }
22	    } catch {
23	      // Fall back to IP key.
24	    }
25	  }
26	
27	  return `ip:${request.ip}`;
28	}
29	
30	export function createUserRateLimitMiddleware(app: FastifyInstance): preHandlerHookHandler {
31	  const maxRequestsPerMinute = getConfig().RATE_LIMIT_MAX_REQUESTS_PER_MINUTE;
32	  const windowMs = 60_000;
33	
34	  return async function userRateLimit(request: FastifyRequest, reply: FastifyReply): Promise<void> {
35	    const key = await resolveRateLimitKey(app, request);
36	    const now = Date.now();
37	    const current = buckets.get(key);
38	
39	    if (!current || current.resetAt <= now) {
40	      buckets.set(key, {
41	        count: 1,
42	        resetAt: now + windowMs
43	      });
44	      return;
45	    }
46	
47	    if (current.count >= maxRequestsPerMinute) {
48	      const retryAfterSeconds = Math.max(1, Math.ceil((current.resetAt - now) / 1000));
49	      reply.header('Retry-After', String(retryAfterSeconds));
50	      reply.code(429).send({ message: 'Too many requests' });
51	      return;
52	    }
53	
54	    current.count += 1;
55	
56	    if (buckets.size > 5000) {
57	      for (const [bucketKey, bucket] of buckets.entries()) {
58	        if (bucket.resetAt <= now) {
59	          buckets.delete(bucketKey);
60	        }
61	      }
62	    }
63	  };
64	}
