6	function parseDurationToSeconds(value: string | undefined, fallbackSeconds: number): number {
7	  if (!value) {
8	    return fallbackSeconds;
9	  }
10	
11	  const trimmed = value.trim();
12	  const direct = Number(trimmed);
13	  if (Number.isFinite(direct) && direct > 0) {
14	    return Math.floor(direct);
15	  }
16	
17	  const match = trimmed.match(/^(\d+)([smhd])$/i);
18	  if (!match) {
19	    return fallbackSeconds;
20	  }
21	
22	  const amount = Number(match[1]);
23	  const unit = match[2].toLowerCase();
24	
25	  if (unit === 's') {
26	    return amount;
27	  }
28	  if (unit === 'm') {
29	    return amount * 60;
30	  }
31	  if (unit === 'h') {
32	    return amount * 60 * 60;
33	  }
34	
35	  return amount * 24 * 60 * 60;
36	}
37	
38	export function getAuthCookieOptions(): CookieSerializeOptions {
39	  const config = getConfig();
40	  const maxAge = parseDurationToSeconds(config.JWT_ACCESS_EXPIRES_IN, 15 * 60);
41	
42	  return {
43	    httpOnly: true,
44	    secure: config.AUTH_COOKIE_SECURE,
45	    sameSite: config.AUTH_COOKIE_SAME_SITE,
46	    path: '/',
47	    maxAge
48	  };
49	}
