1	#!/bin/sh
2	set -e
3	
4	echo "[backend] Waiting for PostgreSQL readiness"
5	node <<'NODE'
6	const { PrismaClient } = require('./prisma/generated');
7	
8	const prisma = new PrismaClient();
9	
10	function delay(ms) {
11	  return new Promise((resolve) => setTimeout(resolve, ms));
12	}
13	
14	async function waitForDatabase() {
15	  let attempt = 1;
16	
17	  while (true) {
18	    try {
19	      await prisma.$connect();
20	      await prisma.$disconnect();
21	      console.log('[backend] PostgreSQL is reachable');
22	      return;
23	    } catch (error) {
24	      const message = error && error.message ? error.message : String(error);
25	      console.log('[backend] PostgreSQL not ready (attempt ' + attempt + '): ' + message);
26	      attempt += 1;
27	      await delay(1000);
28	    }
29	  }
30	}
31	
32	waitForDatabase().catch(async (error) => {
33	  console.error('[backend] Failed waiting for PostgreSQL', error && error.message ? error.message : error);
34	  try {
35	    await prisma.$disconnect();
36	  } catch (_disconnectError) {
37	    // no-op
38	  }
39	  process.exit(1);
40	});
41	NODE
42	
43	echo "[backend] Applying Prisma migrations"
44	npx prisma migrate deploy
45	
46	echo "[backend] Starting backend"
47	npm run start
48	
