{"command": "docker compose exec frontend sh -c "node -e \"
  (async () => {
    // Step 1: Login
    const loginRes = await fetch('http://127.0.0.1:5173/sign-in', {
      method: 'POST',
      headers: { 'content-type': 'application/x-www-form-urlencoded' },
      body: 'username=qa.admin%40culinary.local&password=QaAdminPass123!',
      redirect: 'manual'
    });
    const cookies = loginRes.headers.getSetCookie?.() ?? [];
    const accessCookie = cookies.find(c => c.startsWith('access_token='));
    console.log('Login status:', loginRes.status);
    console.log('Got cookie:', accessCookie ? 'YES' : 'NO');

    if (!accessCookie) { console.log('FAIL: no cookie'); return; }

    // Step 2: Access protected page with cookie
    const cookieValue = accessCookie.split(';')[0];
    const appRes = await fetch('http://127.0.0.1:5173/', {
      headers: { cookie: cookieValue },
      redirect: 'manual'
    });
    console.log('App page status:', appRes.status);
    console.log('Redirected to sign-in:', appRes.headers.get('location')?.includes('sign-in') ?? false);

    if (appRes.status === 200) {
      console.log('SUCCESS: Authenticated user can access app');
    } else {
      console.log('Location:', appRes.headers.get('location'));
    }
  })();
\""", "description": "End-to-end login flow test", "timeout": 15000}

